INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-6e2f88c7-moex-00154', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲向乙借款新臺幣（下同）20萬元，甲因病死亡未留遺產，乙查得甲有一子丙，在甲死亡前一年， 從甲受贈20萬元，乙是否得向丙請求清償借款？', '["依民法第1148條規定，因甲未留遺產，丙對乙不負清償20萬元責任", "依民法第1148條之1規定，丙受贈的20萬元視為其所得遺產，應負清償責任", "依民法第1173條之規定，丙受贈的20萬元為特種贈與，應負清償責任", "丙對乙不須負任何民事清償責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00155', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-9b7ab1bb', 'sub-promotion-6e2f88c7-02', NULL, 'single_choice', '甲死亡時留下存款新臺幣（下同）30萬元。甲之父母乙丙均拋棄繼承。甲尚有其妹丁、祖母戊、 祖父庚在世。庚應可繼承多少甲的遺產？', '["無", "10萬元", "15萬元", "30萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "f79d180b0fb7", "answer_pdf_sha1": "925f95dadfe6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00156', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-e6abbdc3', 'sub-promotion-6e2f88c7-03', NULL, 'essay', '依據法治國原則，法律規範的內容必須明確。但是在立法時，立法者不
免要使用意義較不明確的法律概念（不確定法律概念）。依據司法院大法
官解釋，當立法者運用不確定法律概念進行立法時，須注意使用的法律
概念應該符合什麼標準，以避免違反法治國原則？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "9d1021038170", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0411", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "立法程序與技術", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00157', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-e6abbdc3', 'sub-promotion-6e2f88c7-03', NULL, 'essay', '一般常認為土地法與民法構成特別法與普通法關係。假定土地法與民法
針對同一事項分別做出不同的規定；而民法的規定，事後修正。此時法
官針對此一事項適用法律時，應優先適用土地法或民法的規定？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "9d1021038170", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0411", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "立法程序與技術", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00158', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-e6abbdc3', 'sub-promotion-6e2f88c7-03', NULL, 'essay', '某縣政府規劃將該縣政府所有之大樓，重建並規劃招商，設置為公有觀
光商業大樓。新建大樓前有一公有廣場。該縣政府規劃將廣場改為表演
場地，以推廣該縣特有之民俗藝術，也藉此招攬觀光客。為達成政策目
的，縣政府官員認為，應制定地方自治法規，規定縣民必須考取表演執
照，始得在該處進行表演，獲取收入。如未有表演執照者在該處自行表
演，縣政府得禁止其表演，並課予最高新臺幣一萬元之罰鍰。依據司法
院大法官解釋與地方制度法，該縣頒布之自治法規，應採取何者規範方
式，始符合憲法與地方制度法之要求？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "9d1021038170", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0411", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "立法程序與技術", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00159', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-e6abbdc3', 'sub-promotion-6e2f88c7-03', NULL, 'essay', '立法院有立法委員想提出對於行政院院長的不信任案，依據憲法增修條
文與立法院職權行使法之規定，應該如何進行不信任案的程序？（15 分）
另外，不信任案可否在立法院召開臨時會時提出？（10 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "9d1021038170", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0411", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "立法程序與技術", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00160', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'essay', '某直轄市政府為提升轄區內公共場所升降機之安全性，制定自治條例明
定升降機應定期安全檢查，檢查合格者除給予書面證書外，另貼上合格
標章，公示檢查日期與效期，以發揮大眾一起監督之效果。惟市政府人
力有限，擬開放民間業者執行安全檢查工作，檢查合格者由業者製發書
面證書交其收執，另為提升合格標章之公信力，規定必須貼用市政府製
作之標章。試問：民間檢查業者代替市政府執行安全檢查工作之法律性
質為何？設置某公共場所升降機之私人業者不服檢查未通過之文書，應
向何者提起行政救濟？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "125", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00161', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-110-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'essay', '生理男甲欲改變性別成為女性，向所在地戶政機關申請性別變更登記。
戶政機關收件後，以內政部曾有令示，欲變更性別者應先行提出變性手
術證明，始得辦理性別變更登記為由，認甲所備文件不齊，函知甲補正
已摘除性器官之證明文件。試問：此通知函之法律性質為何？甲若不服，
應如何提起法律救濟？（25分）
